import type { Metadata } from "next";
import CommuterPassClient from "./CommuterPassClient";

export const metadata: Metadata = {
  title: "定期券の購入・更新 | モバイル定期",
  description:
    "中野〜東京（JR中央線）の通勤定期を継続購入・新規購入するモバイルフロー。区間・経由・種類・期間・利用開始日を選び、金額を確認して支払います。",
};

// Server Component シェル。formatValue / onValueChange / onChange など関数 props を
// 渡す対話 UI はすべて "use client" の CommuterPassClient に閉じ込めてあるので、
// next build（RSC のシリアライズ）でも問題にならない。
export default function CommuterPassPage() {
  return (
    <main className="min-h-screen bg-muted/30 text-foreground">
      <CommuterPassClient />
    </main>
  );
}

"use client";

import * as React from "react";
import {
  IconArrowsUpDown,
  IconCreditCard,
  IconWallet,
  IconBuildingStore,
  IconCheck,
  IconInfoCircle,
  IconChevronRight,
  IconChevronLeft,
  IconTrain,
} from "@tabler/icons-react";

import {
  Stepper,
  type StepperStep,
  Card,
  CardHeader,
  CardTitle,
  CardDescription,
  CardContent,
  CardFooter,
  Button,
  Select,
  Badge,
  Separator,
  Banner,
  Alert,
  AlertTitle,
  AlertDescription,
  MetadataList,
  AmountBreakdown,
  type AmountLine,
  DatePicker,
  formatCurrency,
} from "@gunjo/ui";

import {
  STATIONS,
  ROUTE_VIAS,
  CONNECTING_OPTIONS,
  TERM_TABLE,
  KIND_LABEL,
  PAYMENT_LABEL,
  CURRENT_PASS,
  CONTINUE_DISCOUNT,
  type PassKind,
  type PassTerm,
  type PaymentMethod,
  stationByCode,
  viaById,
  monthlyBase,
  termFare,
  effectiveMonthly,
  termSavings,
  expiryDate,
  formatJpDate,
  defaultStartDate,
} from "./data";

/* --------------------------------------------------------------------------
 * 購入ステップ定義
 * ------------------------------------------------------------------------ */
const STEP_KEYS = ["section", "plan", "start", "confirm", "payment"] as const;
type StepKey = (typeof STEP_KEYS)[number];
const STEP_LABELS: Record<StepKey, string> = {
  section: "区間",
  plan: "種類・期間",
  start: "開始日",
  confirm: "確認",
  payment: "支払",
};

const KINDS: PassKind[] = ["commute", "school"];
const TERMS: PassTerm[] = ["1", "3", "6"];

/* --------------------------------------------------------------------------
 * ハンドロール: 価格つき選択カード（@gunjo/ui に「価格・割安つき選択肢カード」が無いため）
 * RadioGroup/ToggleGroup は右寄せの金額＋割安バッジ＋大きいタップ領域を表現できない。
 * role="radio" + aria + キーボード操作を自前で wiring。
 * ------------------------------------------------------------------------ */
interface OptionCardProps {
  selected: boolean;
  onSelect: () => void;
  title: React.ReactNode;
  subtitle?: React.ReactNode;
  price?: React.ReactNode;
  priceNote?: React.ReactNode;
  badge?: React.ReactNode;
  /** ラジオグループ内の roving tabindex 用 */
  tabbable?: boolean;
}

const OptionCard = React.forwardRef<HTMLButtonElement, OptionCardProps>(
  ({ selected, onSelect, title, subtitle, price, priceNote, badge, tabbable = true }, ref) => (
    <button
      ref={ref}
      type="button"
      role="radio"
      aria-checked={selected}
      tabIndex={tabbable ? 0 : -1}
      onClick={onSelect}
      className={[
        "flex w-full items-stretch gap-3 rounded-lg border p-4 text-left transition-colors",
        "min-h-14 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2",
        selected
          ? "border-primary bg-primary-subtle/60 ring-1 ring-primary"
          : "border-border bg-card hover:bg-muted/50",
      ].join(" ")}
    >
      <span
        aria-hidden
        className={[
          "mt-0.5 flex h-5 w-5 shrink-0 items-center justify-center rounded-full border",
          selected ? "border-primary bg-primary text-primary-foreground" : "border-input bg-transparent",
        ].join(" ")}
      >
        {selected ? <IconCheck className="h-3.5 w-3.5" /> : null}
      </span>
      <span className="flex min-w-0 flex-1 flex-col gap-0.5">
        <span className="flex flex-wrap items-center gap-2">
          <span className="font-semibold text-foreground">{title}</span>
          {badge}
        </span>
        {subtitle ? <span className="text-xs text-muted-foreground">{subtitle}</span> : null}
      </span>
      {price != null ? (
        <span className="flex shrink-0 flex-col items-end justify-center text-right">
          <span className="font-bold tabular-nums text-foreground">{price}</span>
          {priceNote ? <span className="text-[11px] text-muted-foreground">{priceNote}</span> : null}
        </span>
      ) : null}
    </button>
  )
);
OptionCard.displayName = "OptionCard";

/** role="radiogroup" のラッパ。矢印キーで選択肢を移動。 */
function OptionRadioGroup({
  label,
  children,
}: {
  label: string;
  children: React.ReactNode;
}) {
  const ref = React.useRef<HTMLDivElement>(null);
  const onKeyDown = (e: React.KeyboardEvent<HTMLDivElement>) => {
    if (!["ArrowDown", "ArrowRight", "ArrowUp", "ArrowLeft", "Home", "End"].includes(e.key)) return;
    const el = ref.current;
    if (!el) return;
    const radios = Array.from(el.querySelectorAll<HTMLButtonElement>('[role="radio"]:not(:disabled)'));
    if (radios.length === 0) return;
    e.preventDefault();
    const current = radios.indexOf(document.activeElement as HTMLButtonElement);
    let next: number;
    if (e.key === "Home") next = 0;
    else if (e.key === "End") next = radios.length - 1;
    else {
      const dir = e.key === "ArrowDown" || e.key === "ArrowRight" ? 1 : -1;
      next = ((current === -1 ? 0 : current) + dir + radios.length) % radios.length;
    }
    radios[next].focus();
    radios[next].click();
  };
  return (
    <div ref={ref} role="radiogroup" aria-label={label} className="flex flex-col gap-2" onKeyDown={onKeyDown}>
      {children}
    </div>
  );
}

/* --------------------------------------------------------------------------
 * メイン
 * ------------------------------------------------------------------------ */
export default function CommuterPassClient() {
  // 新規 or 継続。継続は現在の定期を起点に既定値を入れる。
  const [purchaseType, setPurchaseType] = React.useState<"continue" | "new">("continue");

  const [stepIndex, setStepIndex] = React.useState(0);
  const stepKey = STEP_KEYS[stepIndex];

  // 区間
  const [fromCode, setFromCode] = React.useState("nakano");
  const [toCode, setToCode] = React.useState("tokyo");
  const [viaId, setViaId] = React.useState(ROUTE_VIAS.find((v) => v.recommended)?.id ?? ROUTE_VIAS[0].id);
  const [connectingId, setConnectingId] = React.useState<string | null>(null);

  // 種類・期間
  const [kind, setKind] = React.useState<PassKind>(CURRENT_PASS.kind);
  const [term, setTerm] = React.useState<PassTerm>("6");

  // 開始日
  const [startDate, setStartDate] = React.useState<Date>(() => defaultStartDate());

  // 支払
  const [payment, setPayment] = React.useState<PaymentMethod>("credit");
  const [purchased, setPurchased] = React.useState(false);

  const from = stationByCode(fromCode);
  const to = stationByCode(toCode);
  const via = viaById(viaId) ?? ROUTE_VIAS[0];
  const connecting = connectingId ? CONNECTING_OPTIONS.find((c) => c.id === connectingId) ?? null : null;

  const monthly = monthlyBase(via, kind, connecting);
  const fare = termFare(monthly, term);
  const continueDiscount = purchaseType === "continue" ? CONTINUE_DISCOUNT : 0;
  const payable = fare - continueDiscount;
  const newExpiry = expiryDate(startDate, term);

  const swap = () => {
    setFromCode(toCode);
    setToCode(fromCode);
  };

  const steps: StepperStep[] = STEP_KEYS.map((k, i) => ({
    label: STEP_LABELS[k],
    state: i < stepIndex ? "completed" : i === stepIndex ? "current" : "upcoming",
  }));

  const canAdvance = stepKey !== "section" || (fromCode !== toCode);
  const goNext = () => setStepIndex((i) => Math.min(i + 1, STEP_KEYS.length - 1));
  const goPrev = () => setStepIndex((i) => Math.max(i - 1, 0));

  /* 金額内訳の行（AmountBreakdown 用） */
  const breakdownLines: AmountLine[] = [
    {
      label: `定期運賃（${KIND_LABEL[kind]}・${TERM_TABLE[term].label}）`,
      amount: kind === "school" ? Math.round(via.baseMonthly * 0.45 * TERM_TABLE[term].factor / 10) * 10 : termFare(via.baseMonthly, term),
      note: `${from?.name}〜${to?.name}（${via.label}）`,
    },
  ];
  if (connecting) {
    breakdownLines.push({
      label: "連絡分",
      amount: termFare(
        kind === "school" ? Math.round(connecting.addMonthly * 0.45) : connecting.addMonthly,
        term
      ),
      note: `${connecting.operator}（${connecting.section}）`,
    });
  }
  if (continueDiscount > 0) {
    breakdownLines.push({
      type: "subtotal",
      label: "小計",
      amount: fare,
    });
    breakdownLines.push({
      label: "継続購入割引",
      amount: continueDiscount,
      kind: "subtract",
      note: "更新手続きの還元",
    });
  }

  /* --------------------- レンダリング: ステップ本体 --------------------- */

  function SectionStep() {
    return (
      <div className="flex flex-col gap-5">
        {purchaseType === "continue" ? (
          <Card className="border-primary/30 bg-primary-subtle/30">
            <CardHeader className="p-4 pb-2">
              <div className="flex items-center justify-between gap-2">
                <CardTitle as="h2" className="flex items-center gap-2 text-base">
                  <IconTrain className="h-5 w-5 text-primary" aria-hidden />
                  現在の定期券
                </CardTitle>
                <Badge variant="info">継続購入</Badge>
              </div>
            </CardHeader>
            <CardContent className="p-4 pt-0">
              <MetadataList
                variant="compact"
                items={[
                  { label: "区間", value: `${CURRENT_PASS.from} 〜 ${CURRENT_PASS.to}` },
                  { label: "経由", value: CURRENT_PASS.viaLabel },
                  { label: "種類", value: `${KIND_LABEL[CURRENT_PASS.kind]}定期・${CURRENT_PASS.termLabel}` },
                  {
                    label: "有効期限",
                    value: (
                      <span className="flex items-center justify-end gap-2">
                        {CURRENT_PASS.expiresOn.replace(/-/g, "/")}
                        <Badge variant="warning">残り14日</Badge>
                      </span>
                    ),
                  },
                ]}
              />
            </CardContent>
          </Card>
        ) : null}

        <div className="flex gap-2" role="radiogroup" aria-label="購入の種別">
          {(["continue", "new"] as const).map((t) => (
            <button
              key={t}
              type="button"
              role="radio"
              aria-checked={purchaseType === t}
              onClick={() => setPurchaseType(t)}
              className={[
                "flex-1 rounded-lg border px-3 py-2 text-sm font-medium transition-colors min-h-11",
                "focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2",
                purchaseType === t ? "border-primary bg-primary text-primary-foreground" : "border-border bg-card text-foreground hover:bg-muted/50",
              ].join(" ")}
            >
              {t === "continue" ? "継続購入" : "新規購入"}
            </button>
          ))}
        </div>

        <Card>
          <CardHeader className="p-4 pb-2">
            <CardTitle as="h2" className="text-base">
              区間の設定
            </CardTitle>
            <CardDescription>出発駅と到着駅、経由を選びます。</CardDescription>
          </CardHeader>
          <CardContent className="flex flex-col gap-3 p-4 pt-0">
            <Select
              label="出発駅"
              value={fromCode}
              onChange={(e) => setFromCode(e.target.value)}
            >
              {STATIONS.map((s) => (
                <option key={s.code} value={s.code}>
                  {s.name}（{s.line}）
                </option>
              ))}
            </Select>

            <div className="flex justify-center">
              <Button
                type="button"
                variant="outline"
                size="sm"
                onClick={swap}
                aria-label="出発駅と到着駅を入れ替える"
              >
                <IconArrowsUpDown className="h-4 w-4" aria-hidden />
                駅を入れ替え
              </Button>
            </div>

            <Select label="到着駅" value={toCode} onChange={(e) => setToCode(e.target.value)}>
              {STATIONS.map((s) => (
                <option key={s.code} value={s.code}>
                  {s.name}（{s.line}）
                </option>
              ))}
            </Select>

            {fromCode === toCode ? (
              <Alert variant="destructive">
                <IconInfoCircle className="h-4 w-4" aria-hidden />
                <AlertTitle>出発駅と到着駅が同じです</AlertTitle>
                <AlertDescription>異なる駅を選んでください。</AlertDescription>
              </Alert>
            ) : null}
          </CardContent>
        </Card>

        <Card>
          <CardHeader className="p-4 pb-2">
            <CardTitle as="h2" className="text-base">
              経由の選択
            </CardTitle>
            <CardDescription>同じ区間でも経路により運賃が異なります。</CardDescription>
          </CardHeader>
          <CardContent className="p-4 pt-0">
            <OptionRadioGroup label="経由">
              {ROUTE_VIAS.map((v, i) => (
                <OptionCard
                  key={v.id}
                  selected={viaId === v.id}
                  tabbable={viaId === v.id || (viaId === undefined && i === 0)}
                  onSelect={() => setViaId(v.id)}
                  title={v.label}
                  subtitle={v.note}
                  badge={v.recommended ? <Badge variant="success">おすすめ</Badge> : undefined}
                  price={`${formatCurrency(v.baseMonthly)}/月`}
                  priceNote="通勤1ヶ月"
                />
              ))}
            </OptionRadioGroup>
          </CardContent>
        </Card>

        <Card>
          <CardHeader className="p-4 pb-2">
            <CardTitle as="h2" className="text-base">
              連絡定期（任意）
            </CardTitle>
            <CardDescription>複数社にまたがる場合に1枚にまとめられます。</CardDescription>
          </CardHeader>
          <CardContent className="p-4 pt-0">
            <OptionRadioGroup label="連絡定期">
              <OptionCard
                selected={connectingId === null}
                onSelect={() => setConnectingId(null)}
                title="連絡定期なし"
                subtitle={`${from?.name}〜${to?.name} のみ`}
              />
              {CONNECTING_OPTIONS.map((c) => (
                <OptionCard
                  key={c.id}
                  selected={connectingId === c.id}
                  onSelect={() => setConnectingId(c.id)}
                  title={c.operator}
                  subtitle={c.section}
                  price={`+${formatCurrency(c.addMonthly)}/月`}
                  priceNote="通勤1ヶ月"
                />
              ))}
            </OptionRadioGroup>
          </CardContent>
        </Card>
      </div>
    );
  }

  function PlanStep() {
    return (
      <div className="flex flex-col gap-5">
        <Card>
          <CardHeader className="p-4 pb-2">
            <CardTitle as="h2" className="text-base">
              種類
            </CardTitle>
          </CardHeader>
          <CardContent className="p-4 pt-0">
            <OptionRadioGroup label="定期の種類">
              {KINDS.map((k) => (
                <OptionCard
                  key={k}
                  selected={kind === k}
                  onSelect={() => setKind(k)}
                  title={`${KIND_LABEL[k]}定期`}
                  subtitle={
                    k === "school"
                      ? "通学証明書の提示が必要です"
                      : "勤務先までの通勤に"
                  }
                  price={`${formatCurrency(monthlyBase(via, k, connecting))}/月`}
                  priceNote="1ヶ月換算"
                />
              ))}
            </OptionRadioGroup>
            {kind === "school" ? (
              <Banner variant="info" icon={<IconInfoCircle className="h-4 w-4" />} className="mt-3 h-auto py-2">
                通学定期は購入時に在学を証明する書類（通学証明書）の登録が必要です。
              </Banner>
            ) : null}
          </CardContent>
        </Card>

        <Card>
          <CardHeader className="p-4 pb-2">
            <CardTitle as="h2" className="text-base">
              期間
            </CardTitle>
            <CardDescription>長い期間ほど割安になります。</CardDescription>
          </CardHeader>
          <CardContent className="p-4 pt-0">
            <OptionRadioGroup label="定期の期間">
              {TERMS.map((t) => {
                const f = termFare(monthly, t);
                const save = termSavings(monthly, t);
                const eff = effectiveMonthly(monthly, t);
                return (
                  <OptionCard
                    key={t}
                    selected={term === t}
                    onSelect={() => setTerm(t)}
                    title={TERM_TABLE[t].label}
                    subtitle={`1ヶ月あたり ${formatCurrency(eff)}`}
                    badge={
                      save > 0 ? (
                        <Badge variant="success">{formatCurrency(save)} おトク</Badge>
                      ) : undefined
                    }
                    price={formatCurrency(f)}
                    priceNote={t === "1" ? "基準" : `${TERM_TABLE[t].label}ぶん`}
                  />
                );
              })}
            </OptionRadioGroup>
          </CardContent>
        </Card>
      </div>
    );
  }

  function StartStep() {
    return (
      <Card>
        <CardHeader className="p-4 pb-2">
          <CardTitle as="h2" className="text-base">
            利用開始日
          </CardTitle>
          <CardDescription>
            {purchaseType === "continue"
              ? "継続の場合、現在の定期の満了日翌日が既定です。"
              : "定期券の使い始める日を選びます。"}
          </CardDescription>
        </CardHeader>
        <CardContent className="flex flex-col gap-4 p-4 pt-0">
          <DatePicker
            value={startDate}
            onValueChange={(d) => d && setStartDate(d)}
            dateFormat="yyyy年M月d日"
            calendarLabel="利用開始日を選択"
            startMonth={new Date(2026, 0)}
            endMonth={new Date(2027, 11)}
          />
          <Separator />
          <MetadataList
            variant="compact"
            items={[
              { label: "利用開始日", value: formatJpDate(startDate) },
              { label: "期間", value: TERM_TABLE[term].label },
              { label: "満了日", value: formatJpDate(newExpiry) },
            ]}
          />
        </CardContent>
      </Card>
    );
  }

  function ConfirmStep() {
    return (
      <div className="flex flex-col gap-5">
        <Card>
          <CardHeader className="p-4 pb-2">
            <CardTitle as="h2" className="text-base">
              内容の確認
            </CardTitle>
          </CardHeader>
          <CardContent className="p-4 pt-0">
            <MetadataList
              items={[
                {
                  label: "区間",
                  value: `${from?.name} 〜 ${to?.name}`,
                },
                { label: "経由", value: via.label },
                ...(connecting
                  ? [{ label: "連絡定期", value: `${connecting.operator}（${connecting.section}）` }]
                  : []),
                { label: "種類", value: `${KIND_LABEL[kind]}定期` },
                { label: "期間", value: TERM_TABLE[term].label },
                { label: "利用開始日", value: formatJpDate(startDate) },
                { label: "満了日", value: formatJpDate(newExpiry) },
                {
                  label: "購入区分",
                  value: purchaseType === "continue" ? "継続購入" : "新規購入",
                },
              ]}
            />
          </CardContent>
        </Card>

        <Card>
          <CardHeader className="p-4 pb-2">
            <CardTitle as="h2" className="text-base">
              金額の内訳
            </CardTitle>
          </CardHeader>
          <CardContent className="p-4 pt-0">
            <AmountBreakdown
              lines={breakdownLines}
              total={{ label: "お支払い金額", amount: payable }}
              formula={
                continueDiscount > 0
                  ? "お支払い金額 = 定期運賃 − 継続購入割引"
                  : undefined
              }
            />
          </CardContent>
        </Card>
      </div>
    );
  }

  function PaymentStep() {
    if (purchased) {
      return (
        <Card className="border-success-border bg-success-subtle/40">
          <CardContent className="flex flex-col items-center gap-3 p-8 text-center">
            <span className="flex h-14 w-14 items-center justify-center rounded-full bg-success-strong text-success-strong-foreground">
              <IconCheck className="h-7 w-7" aria-hidden />
            </span>
            <CardTitle as="h2" className="text-lg">
              購入が完了しました
            </CardTitle>
            <p className="text-sm text-muted-foreground">
              {from?.name}〜{to?.name}（{KIND_LABEL[kind]}・{TERM_TABLE[term].label}）<br />
              {formatJpDate(startDate)} から利用できます。
            </p>
            <p className="text-lg font-bold tabular-nums">{formatCurrency(payable)} を{PAYMENT_LABEL[payment]}で決済しました</p>
          </CardContent>
        </Card>
      );
    }

    const methods: { id: PaymentMethod; icon: React.ReactNode; sub: string }[] = [
      { id: "credit", icon: <IconCreditCard className="h-5 w-5" aria-hidden />, sub: "登録済み ****-1234（VISA）" },
      { id: "suica-sf", icon: <IconWallet className="h-5 w-5" aria-hidden />, sub: "SF残高 ¥3,280" },
      { id: "convenience", icon: <IconBuildingStore className="h-5 w-5" aria-hidden />, sub: "受取番号を発行して窓口で支払い" },
    ];

    return (
      <div className="flex flex-col gap-5">
        <Card>
          <CardHeader className="p-4 pb-2">
            <CardTitle as="h2" className="text-base">
              支払方法
            </CardTitle>
          </CardHeader>
          <CardContent className="p-4 pt-0">
            <OptionRadioGroup label="支払方法">
              {methods.map((m) => (
                <OptionCard
                  key={m.id}
                  selected={payment === m.id}
                  onSelect={() => setPayment(m.id)}
                  title={
                    <span className="flex items-center gap-2">
                      <span className="text-muted-foreground">{m.icon}</span>
                      {PAYMENT_LABEL[m.id]}
                    </span>
                  }
                  subtitle={m.sub}
                />
              ))}
            </OptionRadioGroup>
            {payment === "suica-sf" ? (
              <Banner variant="warning" icon={<IconInfoCircle className="h-4 w-4" />} className="mt-3 h-auto py-2">
                SF残高が不足しています。チャージ後にお支払いください。
              </Banner>
            ) : null}
          </CardContent>
        </Card>

        <Card>
          <CardContent className="p-4">
            <AmountBreakdown
              lines={breakdownLines}
              total={{ label: "お支払い金額", amount: payable }}
            />
          </CardContent>
        </Card>
      </div>
    );
  }

  /* --------------------------- 画面全体 --------------------------- */
  return (
    <div className="mx-auto flex w-full max-w-md flex-col">
      {/* ヘッダ */}
      <header className="sticky top-0 z-10 border-b bg-background/95 px-4 py-3 backdrop-blur">
        <h1 className="text-lg font-bold text-foreground">定期券の購入・更新</h1>
        <p className="text-xs text-muted-foreground">
          {from?.name}〜{to?.name}・{KIND_LABEL[kind]}定期
        </p>
      </header>

      {/* 進捗ステッパー */}
      <nav aria-label="購入ステップ" className="border-b bg-card">
        <Stepper steps={steps} />
      </nav>

      {/* 本体 */}
      <div className="flex-1 px-4 py-5">
        {stepKey === "section" && <SectionStep />}
        {stepKey === "plan" && <PlanStep />}
        {stepKey === "start" && <StartStep />}
        {stepKey === "confirm" && <ConfirmStep />}
        {stepKey === "payment" && <PaymentStep />}
      </div>

      {/* フッタ: 金額サマリ + 進む/戻る */}
      {!purchased ? (
        <footer className="sticky bottom-0 z-10 border-t bg-background/95 px-4 py-3 backdrop-blur">
          <div className="mb-2 flex items-baseline justify-between">
            <span className="text-xs text-muted-foreground">
              {KIND_LABEL[kind]}・{TERM_TABLE[term].label}のお支払い
            </span>
            <span className="text-xl font-bold tabular-nums text-foreground">
              {formatCurrency(payable)}
            </span>
          </div>
          <div className="flex gap-2">
            {stepIndex > 0 ? (
              <Button variant="outline" size="lg" onClick={goPrev} className="flex-1">
                <IconChevronLeft className="h-4 w-4" aria-hidden />
                戻る
              </Button>
            ) : null}
            {stepKey !== "payment" ? (
              <Button
                variant="primary"
                size="lg"
                onClick={goNext}
                disabled={!canAdvance}
                className="flex-[2]"
              >
                次へ
                <IconChevronRight className="h-4 w-4" aria-hidden />
              </Button>
            ) : (
              <Button
                variant="primary"
                size="lg"
                onClick={() => setPurchased(true)}
                className="flex-[2]"
              >
                {formatCurrency(payable)} を支払う
              </Button>
            )}
          </div>
        </footer>
      ) : null}
    </div>
  );
}

