/** 期間ごとの月数換算と「ヶ月ぶんの単価」割引率。6ヶ月が最も割安。 */
export const TERM_TABLE: Record<
  PassTerm,
  { label: string; months: number; /** 月額に対する係数（割引込み） */ factor: number }
> = {
  "1": { label: "1ヶ月", months: 1, factor: 1 },
  // 3ヶ月は概ね5%、6ヶ月は概ね10%安い（通勤定期の一般的な逓減）
  "3": { label: "3ヶ月", months: 3, factor: 2.85 },
  "6": { label: "6ヶ月", months: 6, factor: 5.4 },
};

/** 通学定期は通勤定期より大幅に安い（おおよその割合）。 */
export const SCHOOL_DISCOUNT_FACTOR = 0.45;

/** 継続購入の割引（事務手数料相当の還元、定額） */
export const CONTINUE_DISCOUNT = 110;

