/** いま持っている定期（継続購入の起点） */
export interface CurrentPass {
  kind: PassKind;
  from: string;
  to: string;
  viaLabel: string;
  /** 有効期限 yyyy-MM-dd */
  expiresOn: string;
  termLabel: string;
}

