/* ------------------------------ 計算ロジック ------------------------------ */

export function stationByCode(code: string): Station | undefined {
  return STATIONS.find((s) => s.code === code);
}

export function viaById(id: string): RouteVia | undefined {
  return ROUTE_VIAS.find((v) => v.id === id);
}

/** 1ヶ月あたりの基準額（種類・連絡定期込み） */
export function monthlyBase(
  via: RouteVia,
  kind: PassKind,
  connecting: ConnectingPass | null
): number {
  const main = kind === "school" ? Math.round(via.baseMonthly * SCHOOL_DISCOUNT_FACTOR) : via.baseMonthly;
  const conn = connecting
    ? kind === "school"
      ? Math.round(connecting.addMonthly * SCHOOL_DISCOUNT_FACTOR)
      : connecting.addMonthly
    : 0;
  return main + conn;
}

/** 期間ぶんの定期運賃（割引逓減込み、10円単位に丸め） */
export function termFare(monthly: number, term: PassTerm): number {
  const raw = monthly * TERM_TABLE[term].factor;
  return Math.round(raw / 10) * 10;
}

/** 1ヶ月に均した実質月額（割安さの比較用） */
export function effectiveMonthly(monthly: number, term: PassTerm): number {
  return Math.round(termFare(monthly, term) / TERM_TABLE[term].months);
}

/** 1ヶ月を毎月買い続けた場合との差額（＝割安額） */
export function termSavings(monthly: number, term: PassTerm): number {
  const months = TERM_TABLE[term].months;
  const payAsMonthly = termFare(monthly, "1") * months;
  return payAsMonthly - termFare(monthly, term);
}

/** 利用開始日に期間を足した満了日 */
export function expiryDate(start: Date, term: PassTerm): Date {
  const months = TERM_TABLE[term].months;
  const d = new Date(start.getFullYear(), start.getMonth() + months, start.getDate());
  // 開始日の前日が満了日（定期の一般的な数え方）
  d.setDate(d.getDate() - 1);
  return d;
}

export function formatJpDate(date: Date): string {
  return `${date.getFullYear()}年${date.getMonth() + 1}月${date.getDate()}日`;
}

/** 継続購入の既定開始日 = 現在の定期の満了日翌日 */
export function defaultStartDate(): Date {
  const [y, m, d] = CURRENT_PASS.expiresOn.split("-").map(Number);
  return new Date(y, m - 1, d + 1);
}
